      configurable: true,
      get: () => 480,
    })

    fireEvent.scroll(main)

    fireEvent.click(screen.getByRole('button', { name: /voltar ao topo/i }))

    expect(main.scrollTo).toHaveBeenCalledWith({ top: 0, behavior: 'smooth' })
  })
})

