  },
}))

vi.mock('../lib/model-catalog', () => ({
  fetchOpenRouterModels: (...args: unknown[]) => modelCatalogCardMocks.fetchOpenRouterModels(...args),
  getBestAgentInfo: (...args: unknown[]) => modelCatalogCardMocks.getBestAgentInfo(...args),
