describe('rerankDataJudResultsSemantically', () => {
  function makeSemanticResult(overrides: Partial<DataJudResult> = {}): DataJudResult {
    return {
      tribunal: 'stj',
      tribunalName: 'Superior Tribunal de Justiça',
      numeroProcesso: '0001234-56.2023.8.26.0100',
