import { beforeEach, describe, expect, it, vi } from 'vitest'

const thesisExtractorMocks = vi.hoisted(() => ({
  callLLM: vi.fn(),
  createThesis: vi.fn(),
  listTheses: vi.fn(),
  updateThesis: vi.fn(),
}))

